type tOp = (reqId: int, caller: machine, key: int, podId: int, isWrite: bool, value: int);

// Internal event to drive the proxy processing loop.
event eProxyStep;

machine StorageProxy {
    var db: machine;

    // Queue of logical storage-facing operations received from CacheNodes.
    var q: seq[tOp];
    // At most one inflight storage request per key to maintain response correlation.
    var inflightByKey: map[int, tOp];

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            goto Ready;
        }
    }

    state Ready {
        // CacheNodes send logical storage requests to the proxy with these events.
        on eStorageRead do (req: (caller: machine, key: int, podId: int)) {
            var op: tOp;
            var pending: int;

            op = (reqId = 0, caller = req.caller, key = req.key, podId = req.podId, isWrite = false, value = 0);
            // Enqueue the operation.
            q += (sizeof(q), op);

            pending = sizeof(q);
            announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = false, pending = pending);

            // Drive proxy processing nondeterministically via internal steps.
            send this, eProxyStep;
        }

        on eStorageWrite do (req: (caller: machine, key: int, value: int, podId: int)) {
            var op: tOp;
            var pending: int;

            op = (reqId = 0, caller = req.caller, key = req.key, podId = req.podId, isWrite = true, value = req.value);
            q += (sizeof(q), op);

            pending = sizeof(q);
            announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true, pending = pending);

            send this, eProxyStep;
        }

        // Proxy driver: in each step, either hold or forward one eligible request.
        on eProxyStep do {
            TryOneProxyStep();
        }

        // Storage replies arrive here; proxy delivers logical responses to original CacheNodes.
        on eStorageReadResp do (resp: (key: int, value: int)) {
            var key: int;
            var op: tOp;

            key = resp.key;
            if (key in inflightByKey) {
                op = inflightByKey[key];

                // Announce delivery of the logical response back to the CacheNode.
                announce eMonitorProxyResponseDelivered, (key = op.key, podId = op.podId, isWrite = false);

                // Forward response to original caller CacheNode.
                send op.caller, eStorageReadResp, (key = resp.key, value = resp.value);

                // Clear inflight for this key and continue processing queue.
                inflightByKey -= (key);
                if (sizeof(q) > 0) {
                    send this, eProxyStep;
                }
            }
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var key: int;
            var op: tOp;

            key = resp.key;
            if (key in inflightByKey) {
                op = inflightByKey[key];

                // Announce delivery of the logical response back to the CacheNode.
                announce eMonitorProxyResponseDelivered, (key = op.key, podId = op.podId, isWrite = true);

                // Forward response to original caller CacheNode.
                send op.caller, eStorageWriteResp, (key = resp.key, success = resp.success, value = resp.value);

                inflightByKey -= (key);
                if (sizeof(q) > 0) {
                    send this, eProxyStep;
                }
            }
        }
    }

    fun TryOneProxyStep() {
        var pending: int;
        var i: int;
        var start: int;
        var idx: int;
        var chosen: bool;
        var op: tOp;
        var keyBusy: bool;

        pending = sizeof(q);
        if (pending == 0) {
            return;
        }

        // Nondeterministically hold to model congestion/delay.
        if ($) {
            announce eMonitorProxyHold, (pending = pending);
            // Keep the driver alive while work remains.
            send this, eProxyStep;
            return;
        }

        // Try to forward one request whose key is not inflight yet.
        chosen = false;
        start = choose(pending);
        i = 0;
        while (i < pending) {
            idx = (start + i) % pending;
            op = q[idx];
            keyBusy = (op.key in inflightByKey);
            if (!keyBusy) {
                // Remove from queue at idx.
                q -= (idx);

                // Announce forward and send to storage.
                announce eMonitorProxyForward, (key = op.key, podId = op.podId, isWrite = op.isWrite, pending = sizeof(q));

                inflightByKey[op.key] = op;
                if (op.isWrite) {
                    send db, eStorageWrite, (caller = this, key = op.key, value = op.value, podId = op.podId);
                } else {
                    send db, eStorageRead, (caller = this, key = op.key, podId = op.podId);
                }
                chosen = true;
                break;
            }
            i = i + 1;
        }

        if (!chosen) {
            // All queued ops are blocked on inflight keys; hold this step.
            announce eMonitorProxyHold, (pending = pending);
        }

        // Keep processing opportunities alive while there is queued work.
        if (sizeof(q) > 0) {
            send this, eProxyStep;
        }
    }
}

machine CacheNode {
    var proxy: machine;
    var podId: int;
    var nextReqId: int;

    // Optional local cache (not used to serve reads without storage to preserve LSI).
    var cache: map[int, int];

    // Read de-duplication: at most one inflight read per key; extra clients wait.
    var inflightReadOwner: map[int, machine];
    var readWaiters: map[int, seq[machine]];

    // Write sequencing per key.
    var inflightWriteOwner: map[int, machine];
    var writeQueues: map[int, seq[(client: machine, value: int)]];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;
            nextReqId = 1;
            goto Serving;
        }
    }

    state Serving {
        // Client read: de-duplicate per key and go via proxy/storage for LSI safety.
        on eClientRead do (req: (client: machine, key: int)) {
            var k: int;
            var c: machine;
            var waiters: seq[machine];

            k = req.key;
            c = req.client;

            if (k in inflightReadOwner) {
                // Another read in-flight for this key; enqueue waiter.
                if (!(k in readWaiters)) {
                    waiters = default(seq[machine]);
                } else {
                    waiters = readWaiters[k];
                }
                waiters += (sizeof(waiters), c);
                readWaiters[k] = waiters;
                return;
            }

            inflightReadOwner[k] = c;

            // Announce proxy request issuance and send to proxy.
            announce eMonitorProxyRequestIssued, (key = k, podId = podId, isWrite = false);
            send proxy, eStorageRead, (caller = this, key = k, podId = podId);
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var k: int;
            var val: int;
            var owner: machine;
            var i: int;
            var waiters: seq[machine];

            k = resp.key;
            val = resp.value;

            // Update local cache with latest committed value (for potential future use).
            cache[k] = val;

            if (k in inflightReadOwner) {
                owner = inflightReadOwner[k];
                send owner, eReadResp, (key = k, value = val, fromCache = false);
                inflightReadOwner -= (k);
            }

            if (k in readWaiters) {
                waiters = readWaiters[k];
                i = 0;
                while (i < sizeof(waiters)) {
                    send waiters[i], eReadResp, (key = k, value = val, fromCache = false);
                    i = i + 1;
                }
                readWaiters -= (k);
            }
        }

        // Client write: enqueue per key and ensure only one inflight write per key.
        on eClientWrite do (req: (client: machine, key: int, value: int)) {
            var k: int;
            var c: machine;
            var v: int;
            var q: seq[(client: machine, value: int)];

            k = req.key;
            c = req.client;
            v = req.value;

            if (k in writeQueues) {
                q = writeQueues[k];
            } else {
                q = default(seq[(client: machine, value: int)]);
            }
            q += (sizeof(q), (client = c, value = v));
            writeQueues[k] = q;

            // If no inflight write for this key, start one.
            if (!(k in inflightWriteOwner)) {
                StartNextWrite(k);
            }
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var k: int;
            var success: bool;
            var val: int;
            var owner: machine;
            var q: seq[(client: machine, value: int)];

            k = resp.key;
            success = resp.success;
            val = resp.value;

            // Update cache with committed value if write succeeded.
            if (success) {
                cache[k] = val;
            }

            if (k in inflightWriteOwner) {
                owner = inflightWriteOwner[k];
                send owner, eWriteResp, (key = k, success = success);
                inflightWriteOwner -= (k);
            }

            if (k in writeQueues) {
                q = writeQueues[k];
                if (sizeof(q) > 0) {
                    // Pop the completed request.
                    q -= (0);
                    writeQueues[k] = q;
                }
            }

            // Start next queued write for this key, if any.
            StartNextWrite(k);
        }
    }

    fun StartNextWrite(k: int) {
        var q: seq[(client: machine, value: int)];
        var entry: (client: machine, value: int);
        if (!(k in writeQueues)) {
            return;
        }
        q = writeQueues[k];
        if (sizeof(q) == 0) {
            return;
        }

        entry = q[0];
        inflightWriteOwner[k] = entry.client;

        // Announce proxy request issuance and send to proxy.
        announce eMonitorProxyRequestIssued, (key = k, podId = podId, isWrite = true);
        send proxy, eStorageWrite, (caller = this, key = k, value = entry.value, podId = podId);
    }
}
